// PRELIMINARY — subject to change in design.md
interface CartItem {
  id: string;
  productId: string;
  quantity: number;
  priceAtAdd: number; // historical snapshot
}

interface Cart {
  id: string;
  userId?: string; // null for guest
  items: CartItem[];
  createdAt: Date;
  updatedAt: Date;
}
